"""Apply the reviewed RFV-3E viewBox/alpha journal fix on a feature branch.

This temporary branch bootstrap edits existing large files with exact, fail-closed
string bindings, writes the permanent contract workflow/report, then removes itself.
It is never part of the final pull-request diff.
"""
from __future__ import annotations

from pathlib import Path

ROOT = Path(__file__).resolve().parents[2]


def replace_once(path: Path, old: str, new: str) -> None:
    text = path.read_text(encoding="utf-8")
    count = text.count(old)
    if count != 1:
        raise RuntimeError(f"expected one binding in {path}, found {count}: {old[:80]!r}")
    path.write_text(text.replace(old, new, 1), encoding="utf-8")


