tests = ROOT / "engine/test_transform_journal.py"
replace_once(
    tests,
    '''def test_unmeasured_alpha_or_gradient_forces_changed_stage_rollback(tmp_path: Path) -> None:\n    from app.transform_journal import TransformJournal\n\n    parent = tmp_path / "parent.svg"\n    candidate = tmp_path / "candidate.svg"\n    parent.write_bytes(_square_svg())\n    candidate.write_bytes(_square_svg("<metadata>changed</metadata>"))\n    journal = TransformJournal(\n        parent, _square_source(), required_metrics={"alpha_fidelity"}\n    )\n    accepted, stage = journal.consider_candidate("alpha_unknown", parent, candidate)\n    assert accepted == parent\n    assert stage["status"] == "rolled_back"\n    assert "required_metric_unmeasured" in stage["reason_codes"]\n\n\n''',
    '''def test_unmeasured_alpha_or_gradient_forces_changed_stage_rollback(\n    tmp_path: Path, monkeypatch: pytest.MonkeyPatch,\n) -> None:\n    import app.source_truth as source_truth\n    from app.transform_journal import TransformJournal\n\n    monkeypatch.setattr(source_truth, "render_svg_to_rgba", lambda *_args, **_kwargs: None)\n    parent = tmp_path / "parent.svg"\n    candidate = tmp_path / "candidate.svg"\n    parent.write_bytes(_square_svg())\n    candidate.write_bytes(_square_svg("<metadata>changed</metadata>"))\n    journal = TransformJournal(\n        parent, _square_source(), required_metrics={"alpha_fidelity"}\n    )\n    accepted, stage = journal.consider_candidate("alpha_unknown", parent, candidate)\n    assert accepted == parent\n    assert stage["status"] == "rolled_back"\n    assert "required_metric_unmeasured" in stage["reason_codes"]\n    assert "alpha_stage_metrics_incomplete" in stage["reason_codes"]\n\n\ndef test_alpha_preserving_viewbox_restore_is_accepted(\n    tmp_path: Path, monkeypatch: pytest.MonkeyPatch,\n) -> None:\n    import app.fidelity as fidelity\n    import app.source_truth as source_truth\n    from app.pipeline import _restore_source_dimensions\n    from app.transform_journal import TransformJournal\n\n    source = _square_source()\n    monkeypatch.setattr(fidelity, "render_svg_to_rgb", lambda *_args, **_kwargs: source.copy())\n\n    def stable_alpha(_path: Path, width: int, height: int) -> np.ndarray:\n        rgba = np.zeros((height, width, 4), dtype=np.uint8)\n        rgba[24:104, 24:104, :3] = (227, 0, 11)\n        rgba[24:104, 24:104, 3] = 255\n        return rgba\n\n    monkeypatch.setattr(source_truth, "render_svg_to_rgba", stable_alpha)\n    path = tmp_path / "transparent-no-viewbox.svg"\n    path.write_bytes(\n        b'<svg xmlns="http://www.w3.org/2000/svg" width="128" height="128">'\n        b'<path fill="#e3000b" d="M24 24H104V104H24Z"/></svg>'\n    )\n    journal = TransformJournal(\n        path, source, required_metrics={"alpha_fidelity"},\n    )\n    accepted, _report, stage = journal.run_in_place(\n        "restore_source_dimensions",\n        path,\n        lambda candidate: _restore_source_dimensions(\n            candidate, {"width": 128, "height": 128},\n        ),\n    )\n\n    assert accepted\n    assert stage["status"] == "accepted"\n    assert stage["required_unmeasured"] == []\n    assert stage["alpha_comparison"]["alpha_iou"] == pytest.approx(1.0)\n    assert stage["alpha_comparison"]["alpha_mae"] == pytest.approx(0.0)\n    assert "_render_alpha" not in stage["before_metrics"]\n    assert "_render_alpha" not in stage["after_metrics"]\n    assert ET.fromstring(path.read_bytes()).get("viewBox") == "0 0 128 128"\n\n\ndef test_alpha_plane_regression_is_rolled_back_even_when_rgb_is_identical(\n    tmp_path: Path, monkeypatch: pytest.MonkeyPatch,\n) -> None:\n    import app.fidelity as fidelity\n    import app.source_truth as source_truth\n    from app.transform_journal import TransformJournal\n\n    source = _square_source()\n    monkeypatch.setattr(fidelity, "render_svg_to_rgb", lambda *_args, **_kwargs: source.copy())\n\n    def rendered_alpha(path: Path, width: int, height: int) -> np.ndarray:\n        rgba = np.zeros((height, width, 4), dtype=np.uint8)\n        loss = b"alpha-loss" in Path(path).read_bytes()\n        lo, hi = (36, 92) if loss else (24, 104)\n        rgba[lo:hi, lo:hi, :3] = (227, 0, 11)\n        rgba[lo:hi, lo:hi, 3] = 255\n        return rgba\n\n    monkeypatch.setattr(source_truth, "render_svg_to_rgba", rendered_alpha)\n    parent = tmp_path / "parent.svg"\n    candidate = tmp_path / "candidate.svg"\n    parent.write_bytes(_square_svg())\n    candidate.write_bytes(_square_svg("<metadata>alpha-loss</metadata>"))\n    journal = TransformJournal(\n        parent, source, required_metrics={"alpha_fidelity"},\n    )\n    accepted, stage = journal.consider_candidate("alpha_loss", parent, candidate)\n\n    assert accepted == parent\n    assert stage["status"] == "rolled_back"\n    assert set(stage["reason_codes"]) & {"alpha_iou_regression", "alpha_mae_regression"}\n    assert stage["required_unmeasured"] == []\n    assert stage["alpha_comparison"]["alpha_iou"] < 0.995\n\n\n''',
)


workflow = ROOT / ".github/workflows/real-world-fidelity-rfv3e-viewbox-fix.yml"
workflow.write_text('''name: Real-world fidelity RFV-3E viewBox alpha-journal fix\n\non:\n  pull_request:\n    paths:\n      - ".github/workflows/real-world-fidelity-rfv3e-viewbox-fix.yml"\n      - "engine/app/transform_journal.py"\n      - "engine/test_transform_journal.py"\n      - "docs/real_world_fidelity/rfv-3e-exact-metric-path-viewbox-fix.md"\n\npermissions:\n  contents: read\n\nconcurrency:\n  group: rfv3e-viewbox-fix-${{ github.event.pull_request.number || github.ref }}\n  cancel-in-progress: true\n\njobs:\n  rfv3e-viewbox-alpha-journal-fix:\n    runs-on: ubuntu-latest\n    timeout-minutes: 45\n    env:\n      PYTHONPATH: engine\n    steps:\n      - name: Run actions/checkout@v4\n        uses: actions/checkout@v4\n        with:\n          fetch-depth: 0\n\n      - name: Run actions/setup-python@v5\n        uses: actions/setup-python@v5\n        with:\n          python-version: "3.12"\n          cache: pip\n          cache-dependency-path: engine/requirements.txt\n\n      - name: Install production test dependencies\n        run: python -m pip install -r engine/requirements.txt pytest\n\n      - name: Compile changed production contract\n        run: python -m py_compile engine/app/transform_journal.py engine/test_transform_journal.py\n\n      - name: Run complete transform journal contract\n        working-directory: engine\n        run: pytest -q test_transform_journal.py\n\n      - name: Verify alpha-preserving viewBox acceptance and alpha rollback\n        working-directory: engine\n        run: >-\n          pytest -q test_transform_journal.py\n          -k 'alpha_preserving_viewbox_restore or alpha_plane_regression or unmeasured_alpha'\n\n      - name: Verify narrow production diff scope\n        shell: bash\n        run: |\n          set -euo pipefail\n          git fetch origin "${{ github.base_ref }}"\n          changed="$(git diff --name-only "origin/${{ github.base_ref }}...HEAD")"\n          while IFS= read -r path; do\n            [ -z "${path}" ] && continue\n            case "${path}" in\n              .github/workflows/real-world-fidelity-rfv3e-viewbox-fix.yml|\\\n              engine/app/transform_journal.py|\\\n              engine/test_transform_journal.py|\\\n              docs/real_world_fidelity/rfv-3e-exact-metric-path-viewbox-fix.md)\n                ;;\n              *)\n                echo "Unexpected file in RFV-3E viewBox fix diff: ${path}"\n                exit 1\n                ;;\n            esac\n          done <<< "${changed}"\n\n      - name: Confirm forbidden contracts are unchanged\n        shell: bash\n        run: |\n          set -euo pipefail\n          git diff --exit-code "origin/${{ github.base_ref }}...HEAD" -- \\\n            engine/app/final_artifact_evaluator.py \\\n            engine/app/pipeline.py \\\n            engine/benchmark \\\n            docs/real_world_fidelity/evidence/rfv3_quality_decision.json \\\n            docs/real_world_fidelity_roadmap.json\n\n      - name: Confirm release remains NO-GO and RFV-4 blocked\n        run: |\n          python - <<'PY'\n          import json\n          from pathlib import Path\n\n          roadmap = json.loads(Path('docs/real_world_fidelity_roadmap.json').read_text())\n          decision = json.loads(\n              Path('docs/real_world_fidelity/evidence/rfv3_quality_decision.json').read_text()\n          )\n          assert roadmap['phases'][2]['status'] == 'pending'\n          assert roadmap['phases'][3]['status'] == 'pending'\n          assert decision['release_decision'] == 'no_go'\n          assert decision['rfv4_allowed'] is False\n          print('RFV-3 remains pending; RFV-4 remains blocked')\n          PY\n''', encoding="utf-8")

report = ROOT / "docs/real_world_fidelity/rfv-3e-exact-metric-path-viewbox-fix.md"
report.write_text('''# RFV-3E exact metric path viewBox alpha-journal fix\n\n## Evidence binding\n\nThis narrow production fix follows the diagnostics merged in PR #104 at main SHA\n`d41c23c7382db9d7bd317a37f8b6b77c9f5a7689`. The source live evidence remains\nPR #103, RFV-3B run `29623130466`, aggregate artifact `8424383328`, digest\n`sha256:ff45ec277fe8162f3be117cff76ec3fb82e3cafc4d563941fcabd145ff1e8cb0`.\n\nAffected cases: `qualification-public-10`, `qualification-public-14`, and\n`qualification-public-18`. Their repeat-level evaluator reports stopped at\n`viewbox_missing` because the valid source-dimension repair was rolled back by the\nrequired-but-unmeasured `alpha_fidelity` journal gate.\n\n## Fix\n\n`TransformJournal` now captures a bounded RGBA render alpha plane for every parent\nand candidate whenever `alpha_fidelity` is required. The private ndarray remains in\nthe in-request measurement cache only; public journal reports contain hashes,\ncoverage, and parent/candidate alpha comparison metrics, never raw pixel arrays.\n\nThe parent and candidate alpha planes are compared with the existing\n`alpha_plane_metrics` implementation. The existing final-artifact image-class alpha\nhard gates are reused without modification:\n\n- alpha IoU below the existing class threshold rolls the candidate back;\n- alpha MAE above the existing class threshold rolls the candidate back;\n- missing RGBA rendering remains `required_metric_unmeasured` and fail-closed.\n\nA viewBox/source-coordinate repair that preserves alpha and the existing structural,\nvisual, topology, seam, and complexity gates is accepted. A candidate whose RGB\nrender is identical but whose alpha plane regresses is explicitly rolled back.\n\n## Non-scope\n\nThis change does not alter the vectorizer, winner selection, serializer, final\nevaluator implementation or thresholds, corpus identity, repeat count, timeout,\nretry policy, canonical release decision, or RFV-4 state.\n\n## Required validation\n\nBecause production journal behavior changes, the unchanged 24-case corpus must run\nthree repeats per case. The release decision remains `no_go` and `rfv4_allowed`\nremains `false` until the complete RFV-3B aggregate is reviewed.\n''', encoding="utf-8")

